  1→/**
  2→ * Observer agent: verifies entity state changes and surfaces observations.
  3→ *
  4→ * Owns the full verification pipeline: deterministic + LLM reasoning.
  5→ * Called by observer-route.ts (HTTP adapter) for each entity event.
  6→ *
  7→ * Pipeline: receive event -> gather signals -> deterministic verdict
  8→ *           -> (optional) LLM reasoning -> persist observation
  9→ */
 10→
 11→import { RecordId, type Surreal } from "surrealdb";
 12→import type { LanguageModel } from "ai";
 13→import { createObservation, type ObserveTargetRecord } from "../../observation/queries";
 14→import { queryExistingObserverObservationsForEntity } from "../../observer/graph-scan";
 15→import { logInfo } from "../../http/observability";
 16→import { gatherTaskSignals } from "../../observer/external-signals";
 17→import { checkCiStatus } from "../../observer/external-signals";
 18→import {
 19→  compareTaskCompletion,
 20→  compareIntentCompletion,
 21→  compareCommitStatus,
 22→  compareDecisionConfirmation,
 23→  compareObservationPeerReview,
 24→  shouldSkipLlm,
 25→  applyLlmVerdict,
 26→  type VerificationResult,
 27→  type IntentSignals,
 28→  type DecisionSignals,
 29→  type ObservationPeerReviewSignals,
 30→} from "../../observer/verification-pipeline";
 31→import { buildEntityContext } from "../../observer/context-loader";
 32→import { generateVerificationVerdict, generatePeerReviewVerdict } from "../../observer/llm-reasoning";
 33→import { parseEntityRef } from "../../observer/evidence-validator";
 34→
 35→// ---------------------------------------------------------------------------
 36→// Types
 37→// ---------------------------------------------------------------------------
 38→
 39→export type ObserverVerdict = "match" | "mismatch" | "inconclusive";
 40→
 41→export type ObserverAgentOutput = {
 42→  observations_created: number;
 43→  verdict: ObserverVerdict;
 44→  evidence: string[];
 45→};
 46→
 47→export type ObserverAgentInput = {
 48→  surreal: Surreal;
 49→  workspaceRecord: RecordId<"workspace", string>;
 50→  entityTable: string;
 51→  entityId: string;
 52→  entityBody?: Record<string, unknown>;
 53→  observerModel?: LanguageModel;
 54→};
 55→
 56→// ---------------------------------------------------------------------------
 57→// Agent entry point
 58→// ---------------------------------------------------------------------------
 59→
 60→export async function runObserverAgent(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
 61→  const { entityTable } = input;
 62→
 63→  switch (entityTable) {
 64→    case "task":
 65→      return verifyTask(input);
 66→    case "intent":
 67→      return verifyIntent(input);
 68→    case "git_commit":
 69→      return verifyCommit(input);
 70→    case "decision":
 71→      return verifyDecision(input);
 72→    case "observation":
 73→      return peerReviewObservation(input);
 74→    default:
 75→      return {
 76→        observations_created: 0,
 77→        verdict: "inconclusive",
 78→        evidence: [`Entity type '${entityTable}' verification not yet implemented`],
 79→      };
 80→  }
 81→}
 82→
 83→// ---------------------------------------------------------------------------
 84→// Task verification (deterministic + LLM)
 85→// ---------------------------------------------------------------------------
 86→
 87→async function verifyTask(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
 88→  const { surreal, workspaceRecord, entityId: taskId, entityBody: body, observerModel } = input;
 89→  const taskRecord = new RecordId("task", taskId);
 90→  const evidence: string[] = [];
 91→
 92→  // Deterministic: gather external signals (commits, CI)
 93→  const signalsResult = await gatherTaskSignals(surreal, taskId);
 94→  evidence.push(`Commits found: ${signalsResult.hasCommits}`);
 95→  evidence.push(`Signal count: ${signalsResult.signals.length}`);
 96→
 97→  const deterministicResult = compareTaskCompletion(signalsResult);
 98→  evidence.push(`Verdict: ${deterministicResult.verdict}`);
 99→  evidence.push(deterministicResult.text);
100→
101→  // LLM reasoning path
102→  if (observerModel) {
103→    const skipDeterministic = await loadWorkspaceSkipSetting(surreal, workspaceRecord);
104→
105→    if (shouldSkipLlm(deterministicResult, skipDeterministic)) {
106→      logInfo("observer.llm.skip", "LLM skipped: deterministic match + CI passing", { taskId });
107→    } else {
108→      const context = await buildEntityContext(surreal, workspaceRecord, "task", taskId, body);
109→
110→      // Only invoke LLM when there are decisions to check against.
111→      // Without decisions, semantic verification has nothing to compare --
112→      // the deterministic CI-based verdict should stand.
113→      if (context.relatedDecisions.length === 0) {
114→        logInfo("observer.llm.skip", "LLM skipped: no related decisions to verify against", { taskId });
115→        await persistObservation(surreal, workspaceRecord, [taskRecord as ObserveTargetRecord], deterministicResult);
116→        return {
117→          observations_created: 1,
118→          verdict: deterministicResult.verdict,
119→          evidence,
120→        };
121→      }
122→
123→      const llmVerdict = await generateVerificationVerdict(observerModel, context, deterministicResult);
124→      const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
125→
126→      // Link contradicted decisions via observes edges
127→      const additionalRecords = extractDecisionRecords(llmVerdict?.evidence_refs);
128→
129→      await persistObservation(surreal, workspaceRecord, [taskRecord as ObserveTargetRecord, ...additionalRecords], finalVerdict);
130→
131→      return {
132→        observations_created: 1,
133→        verdict: finalVerdict.verdict,
134→        evidence,
135→      };
136→    }
137→  }
138→
139→  // Deterministic-only path
140→  await persistObservation(surreal, workspaceRecord, [taskRecord as ObserveTargetRecord], deterministicResult);
141→
142→  return {
143→    observations_created: 1,
144→    verdict: deterministicResult.verdict,
145→    evidence,
146→  };
147→}
148→
149→// ---------------------------------------------------------------------------
150→// Intent verification (deterministic only)
151→// ---------------------------------------------------------------------------
152→
153→async function verifyIntent(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
154→  const { surreal, workspaceRecord, entityId: intentId, entityBody: body } = input;
155→  const intentRecord = new RecordId("intent", intentId);
156→
157→  const intentSignals = await gatherIntentSignals(surreal, intentId, body);
158→  const result = compareIntentCompletion(intentSignals);
159→
160→  await persistObservation(surreal, workspaceRecord, [intentRecord as ObserveTargetRecord], result);
161→
162→  return {
163→    observations_created: 1,
164→    verdict: result.verdict,
165→    evidence: [result.text],
166→  };
167→}
168→
169→// ---------------------------------------------------------------------------
170→// Commit verification (deterministic only)
171→// ---------------------------------------------------------------------------
172→
173→async function verifyCommit(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
174→  const { surreal, workspaceRecord, entityId: commitId, entityBody: body } = input;
175→  const commitRecord = new RecordId("git_commit", commitId);
176→
177→  const sha = (body?.sha as string) ?? "";
178→  const repository = (body?.repository as string) ?? "";
179→
180→  const signal = await checkCiStatus({ id: commitRecord, sha, repository });
181→  const result = compareCommitStatus({ signals: [signal], hasCommits: true });
182→
183→  await persistObservation(surreal, workspaceRecord, [commitRecord as ObserveTargetRecord], result);
184→
185→  return {
186→    observations_created: 1,
187→    verdict: result.verdict,
188→    evidence: [result.text],
189→  };
190→}
191→
192→// ---------------------------------------------------------------------------
193→// Decision verification (deterministic + LLM check against completed tasks)
194→// ---------------------------------------------------------------------------
195→
196→async function verifyDecision(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
197→  const { surreal, workspaceRecord, entityId: decisionId, entityBody: body, observerModel } = input;
198→  const decisionRecord = new RecordId("decision", decisionId);
199→
200→  // Skip initial CREATE events — only verify status transitions
201→  if (!body?.updated_at) {
202→    logInfo("observer.decision.skipped_create", "Skipping decision CREATE event", { decisionId });
203→    return { observations_created: 0, verdict: "inconclusive", evidence: ["Skipped: CREATE event"] };
204→  }
205→
206→  const decisionSignals = await gatherDecisionSignals(surreal, workspaceRecord, body);
207→  const deterministicResult = compareDecisionConfirmation(decisionSignals);
208→
209→  await persistObservation(surreal, workspaceRecord, [decisionRecord as ObserveTargetRecord], deterministicResult);
210→  let observationsCreated = 1;
211→
212→  // LLM: when decision confirmed, check completed tasks against it (concurrent)
213→  if (observerModel && body?.status === "confirmed" && decisionSignals.completedTaskCount > 0) {
214→    const completedTasks = await queryCompletedTasks(surreal, workspaceRecord);
215→
216→    // Build contexts concurrently, then run LLM calls concurrently
217→    const taskContexts = await Promise.all(
218→      completedTasks.map(async (task) => {
219→        const taskId = task.id.id as string;
220→        const taskBody = { title: task.title, description: task.description, status: "completed" };
221→        const context = await buildEntityContext(surreal, workspaceRecord, "task", taskId, taskBody);
222→        return { task, taskId, context };
223→      }),
224→    );
225→
226→    const verdicts = await Promise.allSettled(
227→      taskContexts.map(({ context }) =>
228→        generateVerificationVerdict(observerModel, context, deterministicResult),
229→      ),
230→    );
231→
232→    for (let i = 0; i < verdicts.length; i++) {
233→      const settled = verdicts[i];
234→      if (settled.status === "rejected") {
235→        logInfo("observer.llm.error", "LLM verification failed for task", {
236→          taskId: taskContexts[i].taskId,
237→          error: String(settled.reason),
238→        });
239→        continue;
240→      }
241→
242→      const llmVerdict = settled.value;
243→      if (!llmVerdict || llmVerdict.verdict !== "mismatch") continue;
244→
245→      const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
246→      const taskRecord = new RecordId("task", taskContexts[i].taskId) as ObserveTargetRecord;
247→
248→      // Dedup: skip if observer already has an open observation on this task
249→      const existing = await queryExistingObserverObservationsForEntity(
250→        surreal, workspaceRecord, taskRecord as RecordId<string, string>,
251→      );
252→      if (existing.length > 0) {
253→        logInfo("observer.decision.dedup", "Skipping duplicate mismatch observation", {
254→          decisionId, taskId: taskContexts[i].taskId,
255→        });
256→        continue;
257→      }
258→
259→      await persistObservation(surreal, workspaceRecord, [decisionRecord as ObserveTargetRecord, taskRecord], finalVerdict);
260→      observationsCreated += 1;
261→    }
262→  }
263→
264→  return {
265→    observations_created: observationsCreated,
266→    verdict: deterministicResult.verdict,
267→    evidence: [deterministicResult.text],
268→  };
269→}
270→
271→// ---------------------------------------------------------------------------
272→// Observation peer review (deterministic + LLM)
273→// ---------------------------------------------------------------------------
274→
275→async function peerReviewObservation(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
276→  const { surreal, workspaceRecord, entityId: observationId, entityBody: body, observerModel } = input;
277→  const observationRecord = new RecordId("observation", observationId);
278→
279→  const linkedEntities = await loadObservationLinkedEntities(surreal, observationId);
280→  const peerReviewSignals = gatherPeerReviewSignals(body, linkedEntities.length);
281→  const deterministicResult = compareObservationPeerReview(peerReviewSignals);
282→
283→  // LLM peer review when model available and observation has linked entities
284→  if (observerModel) {
285→    if (linkedEntities.length > 0) {
286→      const llmVerdict = await generatePeerReviewVerdict(
287→        observerModel,
288→        peerReviewSignals.originalText,
289→        peerReviewSignals.originalSeverity,
290→        peerReviewSignals.sourceAgent,
291→        linkedEntities,
292→      );
293→
294→      if (llmVerdict) {
295→        const severity = llmVerdict.verdict === "sound" ? "info" as const
296→          : "warning" as const;
297→
298→        const reviewResult: VerificationResult = {
299→          verdict: llmVerdict.verdict === "sound" ? "match" : llmVerdict.verdict === "unsupported" ? "mismatch" : "inconclusive",
300→          severity,
301→          verified: llmVerdict.verdict === "sound",
302→          text: llmVerdict.reasoning,
303→          source: "llm",
304→          confidence: llmVerdict.confidence,
305→          observationType: "validation",
306→        };
307→
308→        await persistObservation(surreal, workspaceRecord, [observationRecord as ObserveTargetRecord], reviewResult, "llm");
309→
310→        return {
311→          observations_created: 1,
312→          verdict: reviewResult.verdict,
313→          evidence: [reviewResult.text],
314→        };
315→      }
316→
317→      logInfo("observer.llm.fallback", "LLM peer review failed, using deterministic", { observationId });
318→    } else {
319→      logInfo("observer.llm.skip", "LLM peer review skipped: no linked entities", { observationId });
320→    }
321→  }
322→
323→  // Deterministic fallback
324→  await persistObservation(surreal, workspaceRecord, [observationRecord as ObserveTargetRecord], deterministicResult, "peer_review");
325→
326→  return {
327→    observations_created: 1,
328→    verdict: deterministicResult.verdict,
329→    evidence: [deterministicResult.text],
330→  };
331→}
332→
333→// ---------------------------------------------------------------------------
334→// Signal gathering
335→// ---------------------------------------------------------------------------
336→
337→async function gatherIntentSignals(
338→  surreal: Surreal,
339→  intentId: string,
340→  body?: Record<string, unknown>,
341→): Promise<IntentSignals> {
342→  const status = (body?.status as string) ?? "unknown";
343→  const goal = (body?.goal as string) ?? "Unknown intent";
344→
345→  const intentRecord = new RecordId("intent", intentId);
346→  const [traceRows] = await surreal.query<[Array<{ trace_id?: RecordId }>]>(
347→    `SELECT trace_id FROM $intent;`,
348→    { intent: intentRecord },
349→  );
350→
351→  return { status, goal, hasTrace: !!traceRows?.[0]?.trace_id };
352→}
353→
354→async function gatherDecisionSignals(
355→  surreal: Surreal,
356→  workspaceRecord: RecordId<"workspace", string>,
357→  body?: Record<string, unknown>,
358→): Promise<DecisionSignals> {
359→  const status = (body?.status as string) ?? "unknown";
360→  const summary = (body?.summary as string) ?? "Unknown decision";
361→
362→  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
363→    `SELECT count() AS count FROM task WHERE workspace = $ws AND status IN ["completed", "done"] GROUP ALL;`,
364→    { ws: workspaceRecord },
365→  );
366→
367→  return { status, summary, completedTaskCount: taskRows?.[0]?.count ?? 0 };
368→}
369→
370→function gatherPeerReviewSignals(
371→  body?: Record<string, unknown>,
372→  linkedEntityCount = 0,
373→): ObservationPeerReviewSignals {
374→  const originalText = (body?.text as string) ?? "Unknown observation";
375→  const originalSeverity = ((body?.severity as string) ?? "info") as "info" | "warning" | "conflict";
376→  const sourceAgent = (body?.source_agent as string) ?? "unknown_agent";
377→
378→  return {
379→    originalText,
380→    originalSeverity,
381→    sourceAgent,
382→    linkedEntityCount,
383→  };
384→}
385→
386→// ---------------------------------------------------------------------------
387→// DB helpers
388→// ---------------------------------------------------------------------------
389→
390→async function loadWorkspaceSkipSetting(
391→  surreal: Surreal,
392→  workspaceRecord: RecordId<"workspace", string>,
393→): Promise<boolean | undefined> {
394→  const [rows] = await surreal.query<[Array<{ settings?: { observer_skip_deterministic?: boolean } }>]>(
395→    `SELECT settings FROM $ws;`,
396→    { ws: workspaceRecord },
397→  );
398→  return rows?.[0]?.settings?.observer_skip_deterministic;
399→}
400→
401→async function queryCompletedTasks(
402→  surreal: Surreal,
403→  workspaceRecord: RecordId<"workspace", string>,
404→): Promise<Array<{ id: RecordId<"task">; title: string; description?: string }>> {
405→  const [rows] = await surreal.query<[Array<{
406→    id: RecordId<"task">;
407→    title: string;
408→    description?: string;
409→  }>]>(
410→    `SELECT id, title, description, updated_at FROM task
411→     WHERE workspace = $ws AND status IN ["completed", "done"]
412→     ORDER BY updated_at DESC
413→     LIMIT 20;`,
414→    { ws: workspaceRecord },
415→  );
416→  return rows ?? [];
417→}
418→
419→async function loadObservationLinkedEntities(
420→  surreal: Surreal,
421→  observationId: string,
422→): Promise<Array<{ table: string; id: string; title: string; description?: string }>> {
423→  const observationRecord = new RecordId("observation", observationId);
424→
425→  const [rows] = await surreal.query<[Array<{ out: RecordId }>]>(
426→    `SELECT out FROM observes WHERE in = $obs;`,
427→    { obs: observationRecord },
428→  );
429→
430→  if (!rows || rows.length === 0) return [];
431→
432→  const targets = rows.map((r) => r.out);
433→
434→  const [details] = await surreal.query<[Array<{
435→    id: RecordId;
436→    title?: string; summary?: string; text?: string; description?: string;
437→  }>]>(
438→    `SELECT id, title, summary, text, description FROM $records;`,
439→    { records: targets },
440→  );
441→
442→  return (details ?? []).map((d) => ({
443→    table: d.id.table.name,
444→    id: d.id.id as string,
445→    title: d.title ?? d.summary ?? d.text ?? "Unknown",
446→    description: d.description,
447→  }));
448→}
449→
450→// ---------------------------------------------------------------------------
451→// Observation persistence
452→// ---------------------------------------------------------------------------
453→
454→function extractDecisionRecords(evidenceRefs?: string[]): ObserveTargetRecord[] {
455→  if (!evidenceRefs) return [];
456→  const records: ObserveTargetRecord[] = [];
457→  for (const ref of evidenceRefs) {
458→    const parsed = parseEntityRef(ref);
459→    if (parsed && parsed.table === "decision") {
460→      records.push(new RecordId("decision", parsed.id) as ObserveTargetRecord);
461→    }
462→  }
463→  return records;
464→}
465→
466→async function persistObservation(
467→  surreal: Surreal,
468→  workspaceRecord: RecordId<"workspace", string>,
469→  relatedRecords: ObserveTargetRecord[],
470→  result: VerificationResult,
471→  defaultSource = "none",
472→): Promise<void> {
473→  const now = new Date();
474→
475→  // Convert evidence_refs strings to RecordId objects
476→  const evidenceRefRecords: RecordId[] = [];
477→  for (const ref of result.evidenceRefs ?? []) {
478→    const parsed = parseEntityRef(ref);
479→    if (parsed) evidenceRefRecords.push(new RecordId(parsed.table, parsed.id));
480→  }
481→
482→  await createObservation({
483→    surreal,
484→    workspaceRecord,
485→    text: result.text,
486→    severity: result.severity,
487→    sourceAgent: "observer_agent",
488→    observationType: result.observationType ?? "validation",
489→    now,
490→    relatedRecords,
491→    confidence: result.confidence,
492→    evidenceRefs: evidenceRefRecords.length > 0 ? evidenceRefRecords : undefined,
493→    verified: result.verified,
494→    source: result.source ?? defaultSource,
495→  });
496→}
