 50→// ---------------------------------------------------------------------------
 51→// POST /api/workspaces/:workspaceId/learnings
 52→// ---------------------------------------------------------------------------
 53→
 54→type CreateBody = {
 55→  text?: string;
 56→  learning_type?: string;
 57→  priority?: string;
 58→  target_agents?: string[];
 59→};
 60→
 61→async function handleCreateLearning(
 62→  deps: ServerDependencies,
 63→  workspaceId: string,
 64→  request: Request,
 65→): Promise<Response> {
 66→  let body: CreateBody;
 67→  try {
 68→    body = (await request.json()) as CreateBody;
 69→  } catch {
 70→    return jsonError("invalid JSON body", 400);
 71→  }
 72→
 73→  // Validate required fields
 74→  if (!body.text || typeof body.text !== "string" || body.text.trim().length === 0) {
 75→    return jsonError("text is required", 400);
 76→  }
 77→  if (!body.learning_type || !LEARNING_TYPES.includes(body.learning_type as LearningType)) {
 78→    return jsonError(
 79→      `learning_type must be one of: ${LEARNING_TYPES.join(", ")}`,
 80→      400,
 81→    );
 82→  }
 83→
 84→  let workspaceRecord: RecordId<"workspace", string>;
 85→  try {
 86→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 87→  } catch (error) {
 88→    if (error instanceof HttpError) {
 89→      return jsonError(error.message, error.status);
 90→    }
 91→    logError("learning.create.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 92→    return jsonError("failed to resolve workspace", 500);
 93→  }
 94→
 95→  try {
 96→    const now = new Date();
 97→
 98→    // Attempt embedding generation (non-blocking on failure)
 99→    let embedding: number[] | undefined;
100→    try {
101→      embedding = await createEmbeddingVector(
102→        deps.embeddingModel,
103→        body.text,
104→        deps.config.embeddingDimension,
105→      );
106→    } catch (error) {
107→      logWarn("learning.create.embedding_failed", "Embedding generation failed, persisting without", {
108→        workspaceId,
109→        error: error instanceof Error ? error.message : String(error),
110→      });
111→    }
112→
113→    // Run collision detection before creating the learning
114→    const collisionResult = await checkCollisions({
115→      surreal: deps.surreal,
116→      model: deps.extractionModel,
117→      workspaceRecord,
118→      learningText: body.text.trim(),
119→      learningEmbedding: embedding,
120→      source: "human",
121→    });
122→
123→    // Determine status: blocked learnings stay pending, otherwise human-created = active
124→    const shouldBlock = collisionResult.hasBlockingCollision;
125→    const learningRecord = await createLearning({
126→      surreal: deps.surreal,
127→      workspaceRecord,
128→      learning: {
129→        text: body.text.trim(),
130→        learningType: body.learning_type as LearningType,
131→        priority: (body.priority as "low" | "medium" | "high") ?? "medium",
132→        targetAgents: body.target_agents ?? [],
133→        source: "human",
134→        ...(shouldBlock ? { forceStatus: "pending_approval" as const } : {}),
135→      },
136→      now,
137→      embedding,
138→    });
139→
140→    const learningId = learningRecord.id as string;
141→
142→    logInfo("learning.created", "Learning created via HTTP", {
143→      workspaceId,
144→      learningId,
145→      learningType: body.learning_type,
146→      hasEmbedding: embedding !== undefined,
147→      collisions: collisionResult.collisions.length,
148→      blocked: shouldBlock,
149→    });
150→
151→    const responseCollisions: CollisionResult[] = collisionResult.collisions;
152→
153→    return jsonResponse({
154→      learningId,
155→      learning: { id: learningId },
156→      collisions: responseCollisions,
157→    }, 201);
158→  } catch (error) {
159→    logError("learning.create.failed", "Failed to create learning", error, { workspaceId });
160→    return jsonError("failed to create learning", 500);
161→  }
162→}
163→
164→// ---------------------------------------------------------------------------
165→// GET /api/workspaces/:workspaceId/learnings
166→// ---------------------------------------------------------------------------
167→
168→async function handleListLearnings(
169→  deps: ServerDependencies,
170→  workspaceId: string,
171→  request: Request,
172→): Promise<Response> {
173→  let workspaceRecord: RecordId<"workspace", string>;
174→  try {
175→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
176→  } catch (error) {
177→    if (error instanceof HttpError) {
178→      return jsonError(error.message, error.status);
179→    }
180→    logError("learning.list.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
181→    return jsonError("failed to resolve workspace", 500);
182→  }
183→
184→  try {
185→    const url = new URL(request.url);
186→    const statusParam = url.searchParams.get("status") ?? undefined;
187→    const typeParam = url.searchParams.get("type") ?? undefined;
188→    const agentParam = url.searchParams.get("agent") ?? undefined;
189→
190→    const learnings = await listWorkspaceLearnings({
191→      surreal: deps.surreal,
192→      workspaceRecord,
193→      status: statusParam as LearningStatus | undefined,
194→      learningType: typeParam as LearningType | undefined,
195→      agentType: agentParam,
196→    });
197→
198→    // Return snake_case fields to match HTTP contract
199→    const items = learnings.map((l) => ({
200→      id: l.id,
201→      text: l.text,
202→      learning_type: l.learningType,
203→      status: l.status,
204→      source: l.source,
205→      priority: l.priority,
206→      target_agents: l.targetAgents,
207→      ...(l.suggestedBy ? { suggested_by: l.suggestedBy } : {}),
208→      ...(l.patternConfidence !== undefined ? { pattern_confidence: l.patternConfidence } : {}),
209→      created_at: l.createdAt,
210→      ...(l.approvedAt ? { approved_at: l.approvedAt } : {}),
211→      ...(l.dismissedAt ? { dismissed_at: l.dismissedAt } : {}),
212→      ...(l.dismissedReason ? { dismissed_reason: l.dismissedReason } : {}),
213→      ...(l.deactivatedAt ? { deactivated_at: l.deactivatedAt } : {}),
214→    }));
215→
216→    return jsonResponse({ learnings: items }, 200);
217→  } catch (error) {
218→    logError("learning.list.failed", "Failed to list learnings", error, { workspaceId });
219→    return jsonError("failed to list learnings", 500);
220→  }
221→}
222→
223→// ---------------------------------------------------------------------------
224→// POST /api/workspaces/:workspaceId/learnings/:learningId/actions
225→// ---------------------------------------------------------------------------
226→
227→type ActionBody = {
228→  action?: string;
229→  reason?: string;
230→  new_text?: string;
231→};
232→
233→async function handleLearningAction(
234→  deps: ServerDependencies,
235→  workspaceId: string,
236→  learningId: string,
237→  request: Request,
238→): Promise<Response> {
239→  let body: ActionBody;
240→  try {
241→    body = (await request.json()) as ActionBody;
242→  } catch {
243→    return jsonError("invalid JSON body", 400);
244→  }
245→
246→  if (!body.action || !(VALID_ACTIONS as readonly string[]).includes(body.action)) {
247→    return jsonError(
248→      `action must be one of: ${VALID_ACTIONS.join(", ")}`,
249→      400,
250→    );
251→  }
252→
253→  const action = body.action as LearningAction;
254→
255→  let workspaceRecord: RecordId<"workspace", string>;
256→  try {
257→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
258→  } catch (error) {
259→    if (error instanceof HttpError) {
260→      return jsonError(error.message, error.status);
261→    }
262→    logError("learning.action.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
263→    return jsonError("failed to resolve workspace", 500);
264→  }
265→
266→  // Look up the learning
267→  const learningRecord = new RecordId("learning", learningId) as LearningRecord;
268→  let existing: { status: LearningStatus; workspace: RecordId<"workspace", string> } | undefined;
269→  try {
270→    existing = await deps.surreal.select<{
271→      status: LearningStatus;
272→      workspace: RecordId<"workspace", string>;
273→    }>(learningRecord);
274→  } catch {
275→    // select returns undefined if not found
276→  }
277→
278→  if (!existing) {
279→    return jsonError("learning not found", 404);
280→  }
281→
282→  // Verify workspace scope
283→  if ((existing.workspace.id as string) !== (workspaceRecord.id as string)) {
284→    return jsonError("learning not found", 404);
285→  }
286→
287→  // Validate state transition
288→  const transitions = VALID_TRANSITIONS[existing.status];
289→  if (!transitions || !(action in transitions)) {
290→    return jsonError(
291→      `cannot ${action} a learning in status '${existing.status}'`,
292→      409,
293→    );
294→  }
295→
296→  const newStatus = transitions[action];
297→  const now = new Date();
298→
299→  try {
300→    // If approving with new_text, update text first
301→    if (action === "approve" && body.new_text) {
302→      await updateLearningText({
303→        surreal: deps.surreal,
304→        learningRecord,
305→        newText: body.new_text,
306→        now,
307→      });
308→    }
309→
310→    await updateLearningStatus({
311→      surreal: deps.surreal,
312→      workspaceRecord,
313→      learningRecord,
314→      newStatus,
315→      now,
316→      reason: body.reason,
317→    });
318→
319→    logInfo("learning.action.completed", "Learning action completed", {
320→      workspaceId,
321→      learningId,
322→      action,
323→      previousStatus: existing.status,
324→      newStatus,
325→    });
326→
327→    return jsonResponse({ status: newStatus }, 200);
328→  } catch (error) {
329→    logError("learning.action.failed", "Failed to perform learning action", error, {
330→      workspaceId,
331→      learningId,
332→      action,
333→    });
334→    return jsonError("failed to perform action", 500);
335→  }
336→}
