  1→import { type RecordId, type Surreal } from "surrealdb";
  2→import type { ObservationSummary, OnboardingState, SuggestionSummary } from "../../shared/contracts";
  3→import {
  4→  listConversationEntities,
  5→  listWorkspaceOpenQuestions,
  6→  listWorkspaceProjectSummaries,
  7→  listWorkspaceRecentDecisions,
  8→  readEntityName,
  9→  searchEntitiesByEmbedding,
 10→  type ConversationEntity,
 11→  type RankedEntity,
 12→  type WorkspaceDecisionSummary,
 13→  type WorkspaceProjectSummary,
 14→  type WorkspaceQuestionSummary,
 15→} from "../graph/queries";
 16→import { listWorkspaceOpenObservations } from "../observation/queries";
 17→import { listWorkspacePendingSuggestions } from "../suggestion/queries";
 18→import { loadOnboardingSummary } from "../onboarding/onboarding-state";
 19→import type { GraphEntityRecord } from "../extraction/types";
 20→import { loadActiveLearnings } from "../learning/loader";
 21→import { formatLearningsSection } from "../learning/formatter";
 22→
 23→export type DiscussedEntityContext = {
 24→  kind: string;
 25→  name: string;
 26→  status?: string;
 27→};
 28→
 29→export type ChatContext = {
 30→  conversationEntities: ConversationEntity[];
 31→  relevantEntities?: RankedEntity[];
 32→  workspaceDescription?: string;
 33→  workspaceSummary: {
 34→    projects: WorkspaceProjectSummary[];
 35→    recentDecisions: WorkspaceDecisionSummary[];
 36→    openQuestions: WorkspaceQuestionSummary[];
 37→    openObservations: ObservationSummary[];
 38→    pendingSuggestions: SuggestionSummary[];
 39→  };
 40→  onboardingSummary?: string;
 41→  discussedEntity?: DiscussedEntityContext;
 42→  learningsSection?: string;
 43→};
 44→
 45→type ChatContextLoaders = {
 46→  listConversationEntities: typeof listConversationEntities;
 47→  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
 48→  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
 49→  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
 50→  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
 51→  listWorkspacePendingSuggestions: typeof listWorkspacePendingSuggestions;
 52→  loadOnboardingSummary: typeof loadOnboardingSummary;
 53→  loadActiveLearnings: typeof loadActiveLearnings;
 54→};
 55→
 56→export async function buildChatContext(input: {
 57→  surreal: Surreal;
 58→  conversationRecord: RecordId<"conversation", string>;
 59→  workspaceRecord: RecordId<"workspace", string>;
 60→  workspaceDescription?: string;
 61→  loaders?: ChatContextLoaders;
 62→  inheritedEntityIds?: RecordId[];
 63→  discussesRecord?: RecordId;
 64→  userMessageEmbedding?: number[];
 65→}): Promise<ChatContext> {
 66→  const loaders = input.loaders ?? {
 67→    listConversationEntities,
 68→    listWorkspaceProjectSummaries,
 69→    listWorkspaceRecentDecisions,
 70→    listWorkspaceOpenQuestions,
 71→    listWorkspaceOpenObservations,
 72→    listWorkspacePendingSuggestions,
 73→    loadOnboardingSummary,
 74→    loadActiveLearnings,
 75→  };
 76→
 77→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, pendingSuggestions, onboardingSummary, learningsResult] = await Promise.all([
 78→    loaders.listConversationEntities({
 79→      surreal: input.surreal,
 80→      conversationRecord: input.conversationRecord,
 81→      workspaceRecord: input.workspaceRecord,
 82→      limit: 60,
 83→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 84→        ? { inheritedEntityIds: input.inheritedEntityIds }
 85→        : {}),
 86→    }),
 87→    loaders.listWorkspaceProjectSummaries({
 88→      surreal: input.surreal,
 89→      workspaceRecord: input.workspaceRecord,
 90→      limit: 20,
 91→    }),
 92→    loaders.listWorkspaceRecentDecisions({
 93→      surreal: input.surreal,
 94→      workspaceRecord: input.workspaceRecord,
 95→      limit: 12,
 96→    }),
 97→    loaders.listWorkspaceOpenQuestions({
 98→      surreal: input.surreal,
 99→      workspaceRecord: input.workspaceRecord,
100→      limit: 12,
101→    }),
102→    loaders.listWorkspaceOpenObservations({
103→      surreal: input.surreal,
104→      workspaceRecord: input.workspaceRecord,
105→      limit: 10,
106→    }),
107→    loaders.listWorkspacePendingSuggestions({
108→      surreal: input.surreal,
109→      workspaceRecord: input.workspaceRecord,
110→      limit: 10,
111→    }),
112→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
113→    loaders.loadActiveLearnings({
114→      surreal: input.surreal,
115→      workspaceId: input.workspaceRecord.id as string,
116→      agentType: "chat_agent",
117→      ...(input.workspaceDescription ? { contextEmbedding: undefined } : {}),
118→    }),
119→  ]);
120→
121→  // Cross-conversation entity enrichment: find workspace entities relevant to the user's message
122→  let relevantEntities: RankedEntity[] | undefined;
123→  if (input.userMessageEmbedding) {
124→    const queryEmbedding = input.userMessageEmbedding;
125→    const conversationEntityIds = new Set(
126→      conversationEntities.map((e) => e.id),
127→    );
128→    const ranked = await searchEntitiesByEmbedding({
129→      surreal: input.surreal,
130→      workspaceRecord: input.workspaceRecord,
131→      queryEmbedding,
132→      limit: 15,
133→    });
134→    const filtered = ranked.filter((e) => !conversationEntityIds.has(e.id));
135→    if (filtered.length > 0) {
136→      relevantEntities = filtered.slice(0, 10);
137→    }
138→  }
139→
140→  let discussedEntity: DiscussedEntityContext | undefined;
141→  if (input.discussesRecord) {
142→    const entityRecord = input.discussesRecord as GraphEntityRecord;
143→    const name = await readEntityName(input.surreal, entityRecord);
144→    if (name) {
145→      const row = await input.surreal.select<Record<string, unknown>>(entityRecord);
146→      discussedEntity = {
147→        kind: entityRecord.table.name,
148→        name,
149→        ...(row && typeof row.status === "string" ? { status: row.status } : {}),
150→      };
151→    }
152→  }
153→
154→  const learningsSection = formatLearningsSection(learningsResult.learnings);
155→
156→  return {
157→    conversationEntities,
158→    relevantEntities,
159→    ...(input.workspaceDescription ? { workspaceDescription: input.workspaceDescription } : {}),
160→    workspaceSummary: {
161→      projects,
162→      recentDecisions,
163→      openQuestions,
164→      openObservations,
165→      pendingSuggestions,
166→    },
167→    onboardingSummary,
168→    discussedEntity,
169→    ...(learningsSection ? { learningsSection } : {}),
170→  };
171→}
172→
173→function formatConversationEntities(entities: ConversationEntity[]): string {
174→  if (entities.length === 0) {
175→    return "- none";
176→  }
177→
178→  return entities
179→    .slice(0, 20)
180→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
181→    .join("\n");
182→}
183→
184→
185→function formatRelevantEntities(entities: RankedEntity[]): string {
186→  return entities
187→    .map((e) => `- ${e.kind}: ${e.name} (relevance ${e.score.toFixed(2)})`)
188→    .join("\n");
189→}
190→
191→function formatWorkspaceSummary(context: ChatContext): string {
192→  const { projects, recentDecisions, openQuestions, openObservations, pendingSuggestions } = context.workspaceSummary;
193→
194→  const lines: string[] = [];
195→
196→  // Projects: keep names since they're needed for routing
197→  if (projects.length === 0) {
198→    lines.push("- Projects: none");
199→  } else {
200→    lines.push(`- Projects: ${projects.map((p) => p.name).join(", ")}`);
201→  }
202→
203→  // Decisions: count by status
204→  if (recentDecisions.length === 0) {
205→    lines.push("- Decisions: none");
206→  } else {
207→    const statusCounts = new Map<string, number>();
208→    for (const d of recentDecisions) {
209→      statusCounts.set(d.status, (statusCounts.get(d.status) ?? 0) + 1);
210→    }
211→    const breakdown = [...statusCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
212→    lines.push(`- Decisions: ${recentDecisions.length} (${breakdown})`);
213→  }
214→
215→  // Questions: just count
216→  lines.push(`- Open questions: ${openQuestions.length}`);
217→
218→  // Observations: count by severity
219→  if (openObservations.length === 0) {
220→    lines.push("- Observations: none");
221→  } else {
222→    const severityCounts = new Map<string, number>();
223→    for (const o of openObservations) {
224→      severityCounts.set(o.severity, (severityCounts.get(o.severity) ?? 0) + 1);
225→    }
226→    const breakdown = [...severityCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
227→    lines.push(`- Observations: ${openObservations.length} (${breakdown})`);
228→  }
229→
230→  // Suggestions: count by category
231→  if (pendingSuggestions.length === 0) {
232→    lines.push("- Suggestions: none");
233→  } else {
234→    const categoryCounts = new Map<string, number>();
235→    for (const s of pendingSuggestions) {
236→      categoryCounts.set(s.category, (categoryCounts.get(s.category) ?? 0) + 1);
237→    }
238→    const breakdown = [...categoryCounts.entries()].map(([c, n]) => `${n} ${c}`).join(", ");
239→    lines.push(`- Suggestions: ${pendingSuggestions.length} (${breakdown})`);
240→  }
241→
242→  return lines.join("\n");
243→}
244→
245→type SystemPromptOptions = {
246→  isOnboarding?: boolean;
247→  onboardingState?: OnboardingState;
248→  workspaceName?: string;
249→};
250→
251→export function buildSystemPrompt(context: ChatContext, options?: SystemPromptOptions): string {
252→  const sections: string[] = [
253→    "You are the Chat agent for Brain — an agent-native business operating system.",
254→    "You are a **thin orchestrator**: your job is to decide which tools and subagents to invoke, control sequencing, and synthesize user-facing responses.",
255→    "",
256→    "## Core Behavior: Act, Don't Describe",
257→    "When the user describes work to be done, **use your tools to create entities in the graph immediately**. Do NOT:",
258→    "- List what you *could* do and ask for permission",
259→    "- Write prose descriptions of features/tasks without creating them",
260→    "- Ask \"would you like me to help break these down?\" — just break them down",
261→    "- Explain that \"the data model already has X\" — if the user describes structure, they mean THEIR domain, not Brain's internals",
262→    "- Suggest generic next steps without executing them",
263→    "",
264→    "When the user says \"yes\" to creating work items, dispatch the PM agent or use create_work_item. When they describe a decision, use create_provisional_decision. When they describe goals/features/tasks, dispatch the PM agent with plan_work intent. Your value is in *doing*, not *describing what you could do*.",
265→    "",
266→    "## Domain Separation",
267→    "The user's business — whatever they are building, planning, or discussing — is NOT Brain itself.",
268→    "Even if the user's domain uses identical terms (entities, graphs, tasks, features, hierarchy), treat ALL user input as business content to capture in the graph.",
269→    "When the user says \"I want entities: X → Y → Z\" or describes a hierarchy, they are describing THEIR domain model — dispatch the PM agent to plan it as work items.",
270→    "Never explain Brain's data model, architecture, or current entity types unless the user explicitly asks \"how does Brain work?\" or similar.",
271→    "",
272→    "## What This System Is",
273→    "Brain replaces the human as shared memory between agents. Instead of re-explaining context every session, agents read from and write to a knowledge graph. The graph captures every decision, constraint, task, and relationship — so any agent (or the human) can query it and get full context instantly.",
274→    "",
275→    "The user sets strategy and constraints. Agents execute. The graph is shared memory. The feed is where the user governs (reviews pending decisions, resolves conflicts, approves work).",
276→    "",
277→    "## Data Model (Internal Reference)",
278→    "This section describes how YOU store data. Do not explain this to the user — just use it to pick the right tools.",
279→    "The graph has these entity types:",
280→    "",
281→    "**Work hierarchy:** Project → Feature → Task",
282→    "- **Project**: a named initiative with status, description, and embedding. Linked to workspace via `has_project` edge.",
283→    "- **Feature**: a capability or deliverable within a project. Linked via `has_feature` edge.",
284→    "- **Task**: an actionable work item. Can belong to a feature (`has_task`) or directly to a project (`belongs_to`). Has status (open/done/etc), priority, category, optional owner and deadline.",
285→    "",
286→    "**Cross-cutting entities** (can attach to any level via `belongs_to`):",
287→    "- **Decision**: a choice that was made. Status lifecycle: extracted → proposed → provisional → confirmed → superseded. Can conflict with other decisions (`conflicts_with` edge).",
288→    "- **Question**: an open question requiring a choice. Not for informational queries — only for pending decisions.",
289→    "- **Observation**: a lightweight signal (info/warning/conflict) written by agents. Lifecycle: open → acknowledged → resolved. Used for cross-project intelligence (\"this billing decision conflicts with your auth rate limiting\").",
290→    "- **Suggestion**: a proactive agent-to-human proposal. Categories: optimization, risk, opportunity, conflict, missing, pivot. Lifecycle: pending → accepted/dismissed/deferred → converted. Built on accumulated observations via `suggestion_evidence` edges. Use `create_suggestion` for actionable proposals with rationale.",
291→    "",
292→    "**Other entities:** Person (with ownership edges), Meeting, Document, Git Commit, Pull Request.",
293→    "",
294→    "**Key relationships (graph edges):**",
295→    "- `has_project`: workspace → project",
296→    "- `has_feature`: project → feature",
297→    "- `has_task`: feature → task",
298→    "- `belongs_to`: task|decision|question → feature|project",
299→    "- `depends_on`: task|feature → task|feature (blocks/needs/soft)",
300→    "- `conflicts_with`: decision|feature ↔ decision|feature",
301→    "- `owns`: person → task|project|feature",
302→    "- `observes`: observation → project|feature|task|decision|question",
303→    "- `suggests_for`: suggestion → project|feature|task|question|decision",
304→    "- `suggestion_evidence`: suggestion → observation|decision|task|feature|project|question|person|workspace",
305→    "- `superseded_by`: decision → decision",
306→    "",
307→    "## How Data Enters the Graph",
308→    "1. **Agent tools** (primary path): you and other agents write structured data (decisions, observations, work items) directly to the graph via tools. When the user mentions entities, projects, tasks, or decisions, use your tools to create them — there is no automatic extraction.",
309→    "2. **User acceptance**: when you suggest work items, the user can accept them into the graph with one click.",
310→    "",
311→    "When the user describes work, use your tools to create the actual entities.",
312→    "",
313→    "## Architecture: Graph as Communication Bus",
314→    "All agent-to-agent communication happens through the knowledge graph. You do NOT pass data between agents directly.",
315→    "- Each agent reads the graph for context it needs.",
316→    "- Each agent writes its outputs (entities, observations, decisions) directly to the graph.",
317→    "- Subsequent agents read the graph and see prior agents' work.",
318→    "- You synthesize the user-facing response from graph state and tool results.",
319→    "",
320→    "Never assume data from other workspaces.",
321→    "",
322→  ];
323→
324→  // Onboarding mode instructions
325→  if (options?.isOnboarding && options.onboardingState !== "complete") {
326→    if (options.onboardingState === "summary_pending") {
327→      sections.push(
328→        "## Onboarding Mode — Summary",
329→        "The workspace onboarding is wrapping up. Summarize what has been captured so far and ask the user to confirm or add anything else.",
330→        "",
331→        "Current workspace state:",
332→        context.onboardingSummary ?? "No entities captured yet.",
333→        "",
334→      );
335→    } else {
336→      const workspaceName = options.workspaceName;
337→      const topicList = context.workspaceDescription
338→        ? "projects and product areas, people, decisions, tools, bottlenecks."
339→        : "business/venture, projects, people, decisions, tools, bottlenecks.";
340→      sections.push(
341→        "## Onboarding Mode",
342→        "You are onboarding a newly created workspace.",
343→        ...(context.workspaceDescription
344→          ? [
345→            ...(workspaceName ? [`The workspace is named "${workspaceName}".`] : []),
346→            `The workspace is described as: "${context.workspaceDescription}"`,
347→            "Do not ask what the business is — focus on discovering projects and product areas within it.",
348→            "",
349→            "## Workspace ≠ Project — Classification Rules",
350→            ...(workspaceName ? [`"${workspaceName}" is the workspace (the business/brand). NEVER create a project with the same name as the workspace.`] : []),
351→            "What the user describes next are PROJECTS within this workspace — named product areas, modules, or workstreams.",
352→            "When the user sends a heading (e.g. \"DASHBOARD\") with a description and bullet points:",
353→            "- The heading is a **Project** — create it as a project",
354→            "- Bullet points describing capabilities are **Features** within that project",
355→            "- Bullet points with action verbs (implement, build, fix) are **Tasks**",
356→            "Do NOT nest the user's described structure one level too deep (e.g. making the workspace name a project and demoting projects to features).",
357→          ]
358→          : [
359→            "**CRITICAL: The workspace has no description yet.** The user's first messages describe the business or domain — they are NOT naming specific projects.",
360→            "You MUST first understand the business context before creating any project entities.",
361→            "Do NOT dispatch PM agent with plan_work intent until the user has explicitly named specific projects or product areas as distinct from the business itself.",
362→            "Ask the user what specific projects or product areas they are working on within their business. Do NOT interpret the business name or description as a project.",
363→          ]),
364→        "Ask one natural question at a time like a smart colleague, never as a form.",
365→        `Cover these topics over 5-7 turns: ${topicList}`,
366→        "Keep acknowledgment to one sentence max. Ask exactly one concrete follow-up question.",
367→        "",
368→        ...(context.workspaceDescription
369→          ? [
370→            "When the user describes their workspace, create entities directly:",
371→            "- Projects → dispatch PM agent with plan_work intent",
372→            "- Decisions → use create_provisional_decision",
373→            "- Open questions requiring a choice → use create_question (not for informational queries)",
374→            "- People mentioned → note in your response (person creation is handled separately)",
375→          ]
376→          : [
377→            "Once the user names specific projects (distinct from the business itself), create entities:",
378→            "- Projects → dispatch PM agent with plan_work intent",
379→            "- Decisions → use create_provisional_decision",
380→            "- Open questions requiring a choice → use create_question (not for informational queries)",
381→            "- People mentioned → note in your response (person creation is handled separately)",
382→          ]),
383→        "",
384→        "Current workspace state:",
385→        context.onboardingSummary ?? "No entities captured yet.",
386→        "",
387→      );
388→    }
389→  }
390→
391→  sections.push(
392→    "## When to Create Decisions",
393→    "Commitment/selection language: \"let's go with\", \"we decided\", \"we'll use\", \"going with\", \"settled on\".",
394→    "Decision vs feature: choice language (X instead of Y) = decision; description language (we need X) = feature.",
395→    "",
396→    "## When to Create Questions",
397→    "Only for open questions that require a choice or pending decision: \"should we use X or Y?\", \"which approach for Z?\".",
398→    "Do NOT create question entities for informational queries (\"what is blocking X?\", \"how does Y work?\", \"what's the status?\") — answer those directly.",
399→    "One question per topic; if question includes options (X or Y), create one question entity.",
400→    "",
401→    "## When to Create Suggestions",
402→    "Suggestions are proactive agent-to-human proposals. Use `create_suggestion` when you or a subagent notice:",
403→    "- An optimization opportunity (\"task X could be merged with Y\")",
404→    "- A risk or missing element (\"no task covers deployment rollback\")",
405→    "- A conflict between entities (\"decision A contradicts decision B\")",
406→    "- A pivot or strategic opportunity based on accumulated signals",
407→    "Observations are agent-to-agent signals (\"I noticed X\"). Suggestions are agent-to-human proposals (\"You should do Y, because of observations A, B, C\").",
408→    "Link `evidence_entity_ids` to the observations and entities that support the rationale.",
409→    "",
410→    "## When NOT to Create Entities",
411→    "- Casual conversation, greetings, clarifications, status queries",
412→    "- Vague references: \"my project\", \"the feature\", \"the thing\"",
413→    "- User is brainstorming/exploring — wait for convergence",
414→    "",
415→  );
416→
417→  if (context.discussedEntity) {
418→    const entity = context.discussedEntity;
419→    sections.push(
420→      "## Discussed Entity",
421→      "The user opened this conversation to discuss a specific entity.",
422→      `- Kind: ${entity.kind}`,
423→      `- Name: ${entity.name}`,
424→      ...(entity.status ? [`- Status: ${entity.status}`] : []),
425→      "Acknowledge this entity in your first response and help the user with their question about it.",
426→      "",
427→    );
428→  }
429→
430→  if (context.learningsSection) {
431→    sections.push(context.learningsSection, "");
432→  }
433→
434→  sections.push(
435→    "## This Conversation",
436→    "Entities in this conversation:",
437→    formatConversationEntities(context.conversationEntities),
438→    "",
439→  );
440→
441→  if (context.relevantEntities && context.relevantEntities.length > 0) {
442→    sections.push(
443→      "## Related Context",
444→      "Workspace entities relevant to this message (from other conversations):",
445→      formatRelevantEntities(context.relevantEntities),
446→      "",
447→    );
448→  }
449→
450→  sections.push(
451→    "## Workspace Overview",
452→    "Use list_workspace_entities to retrieve full entity listings. Summary:",
453→    formatWorkspaceSummary(context),
454→    "",
455→    "## Response Format",
456→    "You can use markdown in your replies — headings, bold, italics, lists, code blocks, and links are all rendered in the chat UI.",
457→    "Tool results are rendered directly in the chat UI as typed components.",
458→    "When mentioning entities in prose, use markdown links with #entity/ prefix (e.g. [Task Name](#entity/task:id)).",
459→    "",
460→  );
461→
462→  return sections.join("\n");
463→}
