 96→// ---------------------------------------------------------------------------
 97→// Peer review verdict
 98→// ---------------------------------------------------------------------------
 99→
100→export async function generatePeerReviewVerdict(
101→  model: LanguageModel,
102→  originalText: string,
103→  originalSeverity: string,
104→  sourceAgent: string,
105→  linkedEntities: Array<{ table: string; id: string; title: string; description?: string }>,
106→): Promise<PeerReviewVerdict | undefined> {
107→  const start = Date.now();
108→
109→  try {
110→    const entitiesText = linkedEntities.length > 0
111→      ? linkedEntities.map((e) =>
112→          `- [${e.table}:${e.id}] ${e.title}${e.description ? ` — ${e.description}` : ""}`,
113→        ).join("\n")
114→      : "No linked entities.";
115→
116→    const result = await generateObject({
117→      model,
118→      system: OBSERVER_IDENTITY,
119→      schema: peerReviewVerdictSchema,
120→      prompt: `Peer-review this observation from another agent. Evaluate whether its claims are grounded in the cited evidence.
121→
122→## Observation Under Review
123→- Text: "${originalText}"
124→- Severity: ${originalSeverity}
125→- Source Agent: ${sourceAgent}
126→
127→## Cited Evidence (entities linked via observes edges)
128→${entitiesText}
129→
130→## Instructions
131→- "sound" (confidence >= 0.7) = linked entities directly support the claims.
132→- "questionable" (confidence 0.4-0.7) = partial support, some claims go beyond the evidence.
133→- "unsupported" (confidence < 0.4) = claims lack evidence or contradict linked entities.
134→
135→If no entities are linked, the observation has no cited evidence — verdict should be "unsupported" with low confidence.`,
136→      abortSignal: AbortSignal.timeout(30_000),
137→    });
138→
139→    const latencyMs = Date.now() - start;
140→    logInfo("observer.llm.peer_review", "LLM peer review verdict generated", {
141→      latencyMs,
142→      verdict: result.object.verdict,
143→      confidence: result.object.confidence,
144→    });
145→
146→    return result.object;
147→  } catch (error) {
148→    const latencyMs = Date.now() - start;
149→    logError("observer.llm.peer_review_error", "LLM peer review verdict failed", {
150→      error,
151→      latencyMs,
152→    });
153→    return undefined;
154→  }
155→}
