466→async function persistObservation(
467→  surreal: Surreal,
468→  workspaceRecord: RecordId<"workspace", string>,
469→  relatedRecords: ObserveTargetRecord[],
470→  result: VerificationResult,
471→  defaultSource = "none",
472→): Promise<void> {
473→  const now = new Date();
474→
475→  // Convert evidence_refs strings to RecordId objects
476→  const evidenceRefRecords: RecordId[] = [];
477→  for (const ref of result.evidenceRefs ?? []) {
478→    const parsed = parseEntityRef(ref);
479→    if (parsed) evidenceRefRecords.push(new RecordId(parsed.table, parsed.id));
480→  }
481→
482→  await createObservation({
483→    surreal,
484→    workspaceRecord,
485→    text: result.text,
486→    severity: result.severity,
487→    sourceAgent: "observer_agent",
488→    observationType: result.observationType ?? "validation",
489→    now,
490→    relatedRecords,
491→    confidence: result.confidence,
492→    evidenceRefs: evidenceRefRecords.length > 0 ? evidenceRefRecords : undefined,
493→    verified: result.verified,
494→    source: result.source ?? defaultSource,
495→  });
496→}
